138	struct timespec min_diff_time = { .tv_sec = 0, .tv_nsec = 0 };
139	struct timespec max_diff_time = { .tv_sec = 0, .tv_nsec = 0 };
140	
141	struct timespec clock_difftime(struct timespec start, struct timespec end) {
142	  struct timespec temp;
143	
144	  if ((end.tv_nsec-start.tv_nsec)<0) {
145	    temp.tv_sec = end.tv_sec-start.tv_sec-1;
146	    temp.tv_nsec = 1000000000+end.tv_nsec-start.tv_nsec;
147	  } else {
148	    temp.tv_sec = end.tv_sec-start.tv_sec;
149	    temp.tv_nsec = end.tv_nsec-start.tv_nsec;
150	  }
151	
152	  return temp;
153	}
154	
155	void print_difftimes(void)
156	{
157	  LOG_I(HW, "difftimes min = %lu ns ; max = %lu ns\n", min_diff_time.tv_nsec, max_diff_time.tv_nsec);
158	}
