160	void update_difftimes(struct timespec start, struct timespec end) {
161	  struct timespec diff_time = { .tv_sec = 0, .tv_nsec = 0 };
162	  int             changed = 0;
163	  diff_time = clock_difftime(start, end);
164	
165	  if ((min_diff_time.tv_nsec == 0) || (diff_time.tv_nsec < min_diff_time.tv_nsec)) {
166	    min_diff_time.tv_nsec = diff_time.tv_nsec;
167	    changed = 1;
168	  }
169	
170	  if ((max_diff_time.tv_nsec == 0) || (diff_time.tv_nsec > max_diff_time.tv_nsec)) {
171	    max_diff_time.tv_nsec = diff_time.tv_nsec;
172	    changed = 1;
173	  }
174	
175	#if 1
176	
177	  if (changed) print_difftimes();
178	
179	#endif
180	}
